    def _sort_palette(self, sort_palette):
        """
        Reorders this image's palette, remapping pixel data to match, using
        the method given by ``sort_palette``. See :py:meth:`~PIL.Image.Image.quantize`
        for the accepted values of ``sort_palette``.
        """
        mode = self.palette.mode
        mode_len = len(mode)
        palette = self.palette.palette
        colors = [
            tuple(palette[i : i + mode_len])
            for i in range(0, len(palette), mode_len)
        ]

        if sort_palette == "brightness":

            def sort_key(color):
                r, g, b = (color + (0, 0, 0))[:3]
                return r * 299 + g * 587 + b * 114

        elif sort_palette == "rgb":

            def sort_key(color):
                return color[:3]

        elif callable(sort_palette):
            sort_key = sort_palette
        else:
            raise ValueError(
                "sort_palette must be 'brightness', 'rgb', or a callable"
            )

        order = sorted(range(len(colors)), key=lambda i: sort_key(colors[i]))

        mapping = list(range(256))
        for new_index, old_index in enumerate(order):
            mapping[old_index] = new_index

        new_palette_data = bytearray()
        for old_index in order:
            new_palette_data.extend(colors[old_index])

        im = self.point(mapping)

        from . import ImagePalette

        im.palette = ImagePalette.ImagePalette(mode, bytes(new_palette_data))
